#!/usr/bin/env node
'use strict';

// Turns a promptfoo --output JSON into a PR comment that SHOWS the contrast:
// for every rule, what the model produced without the rule vs. with it.
// The diff between the two outputs is the proof the rule actually does something.
//
// Usage: node eval-comment.cjs <results.json>  > eval-comment.md
//
// Tolerant by design â€” if the eval crashed and produced no JSON, it still
// emits a comment so the PR thread says *something* instead of failing silently.

const fs = require('fs');

const MARKER = '<!-- promptfoo-showcase -->';
const RESULTS_PATH = process.argv[2];

function runUrl() {
  const { GITHUB_SERVER_URL, GITHUB_REPOSITORY, GITHUB_RUN_ID } = process.env;
  if (GITHUB_SERVER_URL && GITHUB_REPOSITORY && GITHUB_RUN_ID) {
    return `${GITHUB_SERVER_URL}/${GITHUB_REPOSITORY}/actions/runs/${GITHUB_RUN_ID}`;
  }
  return null;
}

function footer() {
  const url = runUrl();
  const link = url ? `[full eval run â†—](${url})` : 'the Actions run';
  return `\n\n---\n<sub>đź§Ş Generated by \`.github/workflows/eval-packs.yml\`. Each rule is run twice on the same task â€” with the rule in the system prompt and without â€” so the diff between the two outputs isolates the rule's effect. See ${link} for raw logs.</sub>`;
}

function emitFallback(reason) {
  process.stdout.write(
    `${MARKER}\n## đź§Ş Rule behaviour evals\n\n` +
      `âš ď¸Ź The eval run did not produce readable results (${reason}). ` +
      `Nothing to show this time â€” check the workflow logs.` +
      footer() +
      '\n',
  );
}

// Pull the most interesting code out of a model response. Models usually wrap
// code in a ```fence```; we lift the first fenced block so the snippet renders
// cleanly inside our own fence. Falls back to the raw text when there's no fence.
function snippet(output) {
  let text = output;
  if (text == null) {
    return null;
  }
  if (typeof text !== 'string') {
    try {
      text = JSON.stringify(text, null, 2);
    } catch {
      text = String(text);
    }
  }

  // Collect every fenced block. Models often lead with a ```bash npm install```
  // line before the real code, so we skip shell blocks and pick the largest
  // remaining block â€” that's almost always the actual implementation.
  const SHELL_LANGS = new Set([
    'bash', 'sh', 'shell', 'zsh', 'console', 'shell-session', 'powershell', 'ps1', 'bat', 'cmd',
  ]);
  const blocks = [];
  const fenceRe = /```([a-zA-Z0-9_-]*)\n([\s\S]*?)```/g;
  let m;
  while ((m = fenceRe.exec(text)) !== null) {
    blocks.push({ lang: (m[1] || '').toLowerCase(), body: m[2] });
  }

  let lang = 'ts';
  let code = text;
  if (blocks.length > 0) {
    const eligible = blocks.filter((b) => !SHELL_LANGS.has(b.lang));
    const pool = eligible.length > 0 ? eligible : blocks;
    const chosen = pool.reduce((best, b) => (b.body.length > best.body.length ? b : best));
    code = chosen.body;
    if (chosen.lang && !SHELL_LANGS.has(chosen.lang)) {
      lang = chosen.lang;
    }
  }

  code = code.replace(/^\n+/, '').replace(/\n+$/, '');
  // Never let a stray fence inside the slice break our markdown fence.
  code = code.replace(/```/g, "ĘĽĘĽĘĽ");

  const MAX_LINES = 22;
  const MAX_CHARS = 1500;
  let truncated = false;
  let lines = code.split('\n');
  if (lines.length > MAX_LINES) {
    lines = lines.slice(0, MAX_LINES);
    truncated = true;
  }
  code = lines.join('\n');
  if (code.length > MAX_CHARS) {
    code = code.slice(0, MAX_CHARS);
    truncated = true;
  }

  return { lang, code, truncated };
}

function renderSnippet(output, emptyNote) {
  const s = snippet(output);
  if (!s || s.code.trim() === '') {
    return `_${emptyNote}_`;
  }
  const tail = s.truncated ? '\nâ€¦ _(truncated â€” see full run)_' : '';
  return '```' + s.lang + '\n' + s.code + '\n```' + tail;
}

function cleanTask(task) {
  if (!task || typeof task !== 'string') {
    return null;
  }
  const collapsed = task.replace(/\s+/g, ' ').trim();
  return collapsed.length > 280 ? collapsed.slice(0, 277) + 'â€¦' : collapsed;
}

// The llm-rubric judge reason is the gold â€” it's the model explaining *why* the
// ruled output complies. Prefer it over the terse aggregate reason.
function judgeReason(gradingResult) {
  if (!gradingResult) {
    return null;
  }
  const components = Array.isArray(gradingResult.componentResults)
    ? gradingResult.componentResults
    : [];
  const rubric = components.find(
    (c) => c && c.assertion && c.assertion.type === 'llm-rubric' && c.reason,
  );
  let reason = rubric ? rubric.reason : gradingResult.reason;
  if (!reason || typeof reason !== 'string') {
    return null;
  }
  reason = reason.replace(/\s+/g, ' ').trim();
  return reason.length > 400 ? reason.slice(0, 397) + 'â€¦' : reason;
}

function main() {
  if (!RESULTS_PATH || !fs.existsSync(RESULTS_PATH)) {
    return emitFallback('no results file');
  }

  let parsed;
  try {
    parsed = JSON.parse(fs.readFileSync(RESULTS_PATH, 'utf8'));
  } catch (e) {
    return emitFallback('results file was not valid JSON');
  }

  const rows =
    parsed && parsed.results && Array.isArray(parsed.results.results)
      ? parsed.results.results
      : null;
  if (!rows || rows.length === 0) {
    return emitFallback('results file had no test rows');
  }

  // Group rows by rule slug (text before " ["); split into baseline / rule-on.
  const groups = new Map();
  for (const row of rows) {
    const desc =
      (row.description && String(row.description)) ||
      (row.testCase && row.testCase.description) ||
      '(unnamed test)';
    const slug = desc.split(' [')[0].trim();
    const kind = /\[baseline\]/i.test(desc)
      ? 'baseline'
      : /\[rule-on\]/i.test(desc)
        ? 'ruleOn'
        : 'other';

    if (!groups.has(slug)) {
      groups.set(slug, { slug, baseline: [], ruleOn: [], other: [] });
    }
    groups.get(slug)[kind].push(row);
  }

  // A side (baseline / rule-on) "succeeds" if the majority of its repeats passed.
  const aggregate = (list) => {
    if (!list.length) {
      return { present: false, success: false, sample: null };
    }
    const passes = list.filter((r) => r.success).length;
    return {
      present: true,
      success: passes * 2 >= list.length,
      passes,
      total: list.length,
      sample: list[0],
    };
  };

  const sections = [];
  let verified = 0;
  let inconclusive = 0;
  let notTaking = 0;

  for (const group of groups.values()) {
    const baseline = aggregate(group.baseline);
    const ruleOn = aggregate(group.ruleOn);

    let icon;
    let verdict;
    if (ruleOn.present && !ruleOn.success) {
      icon = 'âťŚ';
      verdict =
        'the rule was applied but the output still failed its checks â€” the rule may be too weak to take effect';
      notTaking++;
    } else if (ruleOn.present && ruleOn.success && baseline.present && !baseline.success) {
      icon = 'đźźˇ';
      verdict =
        'the ruled output complies, but the model also complied *without* the rule on this task â€” weak attribution';
      inconclusive++;
    } else if (ruleOn.present && ruleOn.success) {
      icon = 'âś…';
      verdict =
        'without the rule the model produced the disallowed pattern; with it, the output complied';
      verified++;
    } else {
      icon = 'đźźˇ';
      verdict = 'no rule-on result was produced for this rule';
      inconclusive++;
    }

    const task =
      cleanTask(ruleOn.sample && ruleOn.sample.vars && ruleOn.sample.vars.task) ||
      cleanTask(baseline.sample && baseline.sample.vars && baseline.sample.vars.task);

    const baselineOutput = baseline.sample && baseline.sample.response
      ? baseline.sample.response.output
      : undefined;
    const ruleOnOutput = ruleOn.sample && ruleOn.sample.response
      ? ruleOn.sample.response.output
      : undefined;
    const baselineErr = baseline.sample && baseline.sample.error;
    const ruleOnErr = ruleOn.sample && ruleOn.sample.error;

    const reason = judgeReason(ruleOn.sample && ruleOn.sample.gradingResult);

    let block = `<details open>\n<summary><b>${icon} <code>${group.slug}</code></b> â€” ${verdict}</summary>\n\n`;
    if (task) {
      block += `**Task**\n> ${task}\n\n`;
    }
    block += `**Without the rule** â¤µď¸Ź\n`;
    block += renderSnippet(
      baselineOutput,
      baselineErr ? `provider error: ${baselineErr}` : 'no baseline output captured',
    );
    block += `\n\n**With the rule applied** â¤µď¸Ź\n`;
    block += renderSnippet(
      ruleOnOutput,
      ruleOnErr ? `provider error: ${ruleOnErr}` : 'no rule-on output captured',
    );
    if (reason) {
      block += `\n\n> **Judge** _(llm-rubric on the ruled output)_: ${reason}`;
    }
    block += `\n\n</details>`;
    sections.push(block);
  }

  const total = groups.size;
  const summaryBits = [`âś… ${verified} verified`];
  if (inconclusive) {
    summaryBits.push(`đźźˇ ${inconclusive} inconclusive`);
  }
  if (notTaking) {
    summaryBits.push(`âťŚ ${notTaking} not taking effect`);
  }

  const out =
    `${MARKER}\n## đź§Ş Rule behaviour evals\n\n` +
    `Every rule is tested **twice on the same task** â€” once with the rule in the system prompt, once without. ` +
    `The diff between the two outputs is the proof the rule does something.\n\n` +
    `**${total} rule${total === 1 ? '' : 's'} tested** â€” ${summaryBits.join(' Â· ')}\n\n` +
    sections.join('\n\n') +
    footer() +
    '\n';

  process.stdout.write(out);
}

main();
